mapper.select:
SELECT m.id, m.application_material_id, m.textbook_id, m.chapter_id, m.chapter_name, m.view_count, m.download_count, a.name AS applicationMaterialName, a.application_type AS applicationType, tb.textbook_name AS textbookName, te.name AS creatorName, m.creator, m.add_datetime, m.operator, m.operation_datetime FROM application_materials_textbook_mapping m LEFT JOIN application_materials a ON m.application_material_id = a.id LEFT JOIN textbook tb ON m.textbook_id = tb.id LEFT JOIN teacher te ON m.creator = te.id WHERE 1=1
AND m.textbook_id = #{param.textbookId}
AND m.application_material_id = #{param.applicationMaterialId}
AND m.chapter_name LIKE CONCAT('%', #{param.chapterName}, '%')
AND m.chapter_id = #{param.chapterId}
ORDER BY m.chapter_name ASC, m.add_datetime DESC
